import { describe, it, expect } from '@jest/globals';
import { DarkSectorSafe } from './dark-sector-safe';
import { createEngine } from './mesh-engine';
import { dnaToKnot } from './runtime/packed-knot';

describe('DarkSectorSafe', () => {
  it('should store and retrieve arbitrary binary data (Safety Deposit Box mode)', async () => {
    const engine = createEngine('square', 4);
    const safe = new DarkSectorSafe(engine);

    const key1 = 'user:123:private_key';
    const data1 = new Uint8Array([0xDE, 0xAD, 0xBE, 0xEF]);
    
    const key2 = 'user:123:profile_image_atom';
    const data2 = new Uint8Array(1024).fill(0xAA); // Large-ish buffer

    const signals = { uncertainty: 0.5, complexity: 0.5, novelty: 0.5, budgetSlack: 0.5 };

    // Deposit both
    await safe.deposit(key1, data1, signals);
    await safe.deposit(key2, data2, signals);

    expect(safe.dimensionCount).toBe(2);

    // Withdraw and verify integrity
    const result1 = await safe.withdraw(key1);
    const result2 = await safe.withdraw(key2);

    expect(result1).toEqual(data1);
    expect(result2).toEqual(data2);

    // Liquidate one
    await safe.liquidate(key1);
    expect(safe.dimensionCount).toBe(1);
    expect(await safe.withdraw(key1)).toBeNull();

    // Cleanup remaining
    await safe.liquidate(key2);
  });

  it('should handle text-to-safe transitions via PackedKnot encoding', async () => {
    const engine = createEngine('square', 4);
    const safe = new DarkSectorSafe(engine);
    const encoder = new TextEncoder();
    const decoder = new TextDecoder();

    const secretText = 'The quick brown fox jumps over the lazy dog';
    const data = encoder.encode(secretText);
    const signals = { uncertainty: 0.1, complexity: 0.1, novelty: 0.1, budgetSlack: 0.9 }; // Low stress

    await safe.deposit('fox', data, signals);
    const result = await safe.withdraw('fox');
    
    expect(result).not.toBeNull();
    expect(decoder.decode(result!)).toBe(secretText);

    await safe.liquidate('fox');
  });
});
